steps.task:
# Step 3: Compare source vs compressed
# Edit these filenames to match your files:
INPUT="input.mp4"
OUTPUT="${INPUT%.*}-compressed.${INPUT##*.}"

echo "===== Source: $INPUT ====="
ffprobe -v quiet -print_format json -show_format "$INPUT" 2>&1 | node -e "
const d=require('fs').readFileSync('/dev/stdin','utf-8');
const j=JSON.parse(d);
const f=j.format;
console.log('Size: '+(f.size/1048576).toFixed(1)+' MB');
console.log('Duration: '+f.duration+'s');
console.log('Bitrate: '+(f.bit_rate/1000).toFixed(0)+' kbps');
"

echo ""
echo "===== Compressed: $OUTPUT ====="
ffprobe -v quiet -print_format json -show_format "$OUTPUT" 2>&1 | node -e "
const d=require('fs').readFileSync('/dev/stdin','utf-8');
const j=JSON.parse(d);
const f=j.format;
console.log('Size: '+(f.size/1048576).toFixed(1)+' MB');
console.log('Duration: '+f.duration+'s');
console.log('Bitrate: '+(f.bit_rate/1000).toFixed(0)+' kbps');
"

echo ""
source_size=$(ffprobe -v quiet -print_format json -show_format "$INPUT" 2>&1 | node -e "const d=require('fs').readFileSync('/dev/stdin','utf-8');const j=JSON.parse(d);console.log(j.format.size)")
comp_size=$(ffprobe -v quiet -print_format json -show_format "$OUTPUT" 2>&1 | node -e "const d=require('fs').readFileSync('/dev/stdin','utf-8');const j=JSON.parse(d);console.log(j.format.size)")
if [ -n "$source_size" ] && [ -n "$comp_size" ] && [ "$comp_size" -gt 0 ] 2>/dev/null; then
  reduction=$(echo "scale=1; (1 - $comp_size / $source_size) * 100" | bc 2>/dev/null || echo "?")
  echo "📊 压缩率: ${reduction}% 减小"
fi
